mapper.update:
/* 에이전트 활성/비활성 agent.updateAgentUseYn */
UPDATE TB_AGT
SET USE_YN = #{useYn}
WHERE AGENT_ID = #{agentId}

mapper.select:
/* 에이전트 상세 조회 agent.selectAgent */ SELECT A.AGENT_ID , A.AGENT_NM , A.AGENT_TYPE_CD , A.TEMPERATURE , A.TEMP_DEFAULT_YN , A.TOP_P , A.TOP_P_DEFAULT_YN , A.DESCRIPTION , A.SORT_ORD , A.USE_YN , A.LAST_MDF_DT , A.CREATE_DT , A.MODIFY_DT ${dynamicQuery} FROM TB_AGT A
LEFT JOIN TB_AGT_RAG_CFG B ON A.AGENT_ID = B.AGENT_ID
LEFT JOIN TB_AGT_SQL_CFG B ON A.AGENT_ID = B.AGENT_ID
WHERE 1=1 AND A.AGENT_ID = #{agentId}

/* 에이전트 데이터셋 목록 조회 agent.selectAgentDsList */ SELECT A.DATASET_ID , A.DS_NM , A.DESCRIPTION , CASE WHEN AG.DATASET_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS CONN_YN , IFNULL(DOC.DOC_COUNT, 0) AS DOC_COUNT , A.CHUNK_SIZE , A.MODIFY_DT , A.SORT_ORD FROM TB_DS A /* 문서 개수 */ LEFT JOIN ( SELECT DATASET_ID , COUNT(DOC_ID) AS DOC_COUNT FROM TB_DS_DOC GROUP BY DATASET_ID ) DOC ON A.DATASET_ID = DOC.DATASET_ID /* AGENT 연결 여부 */ LEFT JOIN TB_AGT_DS AG ON A.DATASET_ID = AG.DATASET_ID
AND AG.AGENT_ID = #{agentId}
AND 1 = 0
WHERE 1=1 AND A.USE_YN = 'Y' ORDER BY A.SORT_ORD

/* 에이전트 데이터마트 목록 조회 agent.selectAgentDmList */ SELECT CASE WHEN AG.DATAMART_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS CONN_YN , A.DATAMART_ID , A.DM_NM , A.DESCRIPTION , A.DB_TYPE , A.TBL_CNT , A.LAST_VERIFY_DT FROM TB_DM A LEFT JOIN TB_AGT_DM AG ON A.DATAMART_ID = AG.DATAMART_ID
AND AG.AGENT_ID = #{agentId}
AND 1 = 0
WHERE 1=1 AND A.USE_YN = 'Y' ORDER BY A.SORT_ORD

mapper.update:
/* 에이전트 순서 변경 agent.updateAgentOrder */
UPDATE TB_AGT
SET SORT_ORD = CASE AGENT_ID

        WHEN #{item.agentId} THEN #{item.sortOrd}

END
WHERE AGENT_ID IN

    #{item.agentId}

mapper.insert:
/* 에이전트 저장 agent.saveAgent */
INSERT INTO TB_AGT (
    AGENT_ID
    , AGENT_NM
    , AGENT_TYPE_CD
    , TEMPERATURE
    , TEMP_DEFAULT_YN
    , TOP_P
    , TOP_P_DEFAULT_YN
    , DESCRIPTION
    , SORT_ORD
    , USE_YN
    , LAST_MDF_DT
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{agentId}
    , #{agentNm, jdbcType=VARCHAR}
    , #{agentTypeCd, jdbcType=VARCHAR}
    , #{temperature, jdbcType=VARCHAR}
    , #{tempDefaultYn, jdbcType=VARCHAR}
    , #{topP, jdbcType=VARCHAR}
    , #{topPDefaultYn, jdbcType=VARCHAR}
    , #{description, jdbcType=VARCHAR}
    , #{sortOrd, jdbcType=INTEGER}
    , IFNULL(#{useYn, jdbcType=VARCHAR}, 'Y')
    , NOW()
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    AGENT_NM = VALUES(AGENT_NM)
    , TEMPERATURE = VALUES(TEMPERATURE)
    , TEMP_DEFAULT_YN = VALUES(TEMP_DEFAULT_YN)
    , TOP_P = VALUES(TOP_P)
    , TOP_P_DEFAULT_YN = VALUES(TOP_P_DEFAULT_YN)
    , DESCRIPTION = VALUES(DESCRIPTION)
    , SORT_ORD = VALUES(SORT_ORD)
    , LAST_MDF_DT = NOW()
    , MODIFY_DT = NOW()

/* RAG 설정 저장 agent.saveAgentRagCfg */
INSERT INTO TB_AGT_RAG_CFG (
    AGENT_ID
    , SIM_THRESH
    , MAX_SRCH_RSLT
) VALUES (
    #{agentId}
    , #{simThresh, jdbcType=VARCHAR}
    , #{maxSrchRslt, jdbcType=VARCHAR}
)
ON DUPLICATE KEY UPDATE
    SIM_THRESH = VALUES(SIM_THRESH)
    , MAX_SRCH_RSLT = VALUES(MAX_SRCH_RSLT)

mapper.delete:
/* 에이전트 데이터셋 연결 삭제 agent.deleteAgentDs */
DELETE FROM TB_AGT_DS
WHERE AGENT_ID = #{agentId}

mapper.insert:
/* 에이전트 데이터셋 연결 저장 agent.insertAgentDs */
INSERT INTO TB_AGT_DS (
    AGENT_ID
    , DATASET_ID
    , SORT_ORD
) VALUES

    (
        #{agentId}
        , #{item.datasetId}
        , #{item.sortOrd}
    )

/* SQL 설정 저장 agent.saveAgentSqlCfg */
INSERT INTO TB_AGT_SQL_CFG (
    AGENT_ID
    , MODEL_ID
    , MAX_QRY_SEC
    , SQL_VALID_YN
    , READONLY_YN
    , USER_CFRM_YN
) VALUES (
    #{agentId}
    , #{modelId, jdbcType=VARCHAR}
    , #{maxQrySec, jdbcType=VARCHAR}
    , #{sqlValidYn, jdbcType=VARCHAR}
    , #{readonlyYn, jdbcType=VARCHAR}
    , #{userCfrmYn, jdbcType=VARCHAR}
)
ON DUPLICATE KEY UPDATE
    MODEL_ID = VALUES(MODEL_ID)
    , MAX_QRY_SEC = VALUES(MAX_QRY_SEC)
    , SQL_VALID_YN = VALUES(SQL_VALID_YN)
    , READONLY_YN = VALUES(READONLY_YN)
    , USER_CFRM_YN = VALUES(USER_CFRM_YN)

mapper.delete:
